SELECT AVG(access_count) AS average_accesses
FROM (
    SELECT COUNT(access_id) AS access_count
    FROM access_logs
    GROUP BY entrez_gene_id
) AS gene_access_counts;

SELECT users.user_id, users.user_name, data_sharing.shared_with
FROM users
JOIN data_sharing ON users.user_id = data_sharing.user_id;

SELECT gene_symbol, gene_name
FROM genes
WHERE entrez_gene_id = 42;

SELECT access_logs.user_id, access_logs.entrez_gene_id, COUNT(access_logs.access_id) AS total_accesses
FROM access_logs
GROUP BY access_logs.user_id, access_logs.entrez_gene_id;
